state Beliefs:    list[{prop, source, as_of}]
state Desires:    list[{goal, priority, active}]
state Intentions: list[{plan_id, goal, status, rationale}]

function update_beliefs(observations):
    for obs in observations:
        Beliefs.upsert(prop=obs.prop, source=obs.source, as_of=now())
    persist(Beliefs)

function reconsider_desires():
    for d in Desires:
        if satisfied(d.goal, Beliefs): d.active = false
        d.priority = score(d.goal, Beliefs)
    persist(Desires)

function check_intentions():
    for i in Intentions:
        if not consistent(i.plan_id, Beliefs):
            i.status = "abandoned"
            trace.append({event: "abandon", intention: i,
                          reason: "inconsistent_with_beliefs"})
        elif not aligned(i.goal, active_desires(Desires)):
            i.status = "superseded"
    persist(Intentions)

function tick(observations):
    update_beliefs(observations)
    reconsider_desires()
    check_intentions()
    answer = deliberate(Beliefs, Desires, Intentions)
    confidence = model.estimate_certainty(answer)
    return {answer, confidence}

# Why this works: representing mental state as three typed stores makes
# commitments durable across prompts, surfaces contradiction between
# what the agent believes and what it is pursuing, and gives the trace
# a vocabulary auditors can read.
# Related: see `hypothesis-tracking`, `world-model-separation`.

MENU = {
    "revisit-tension":     run_revisit_tension,
    "world-update":        run_world_update,
    "trajectory-note":     run_self_archaeology,
    "propose-experiment":  run_experiment_proposal,
    "rest":                run_no_op,
}
recent_moves = bounded_deque(maxlen=8)

function pick_move(ctx) -> move_id:
    prompt = f"""choose ONE move-id from {list(MENU.keys())}.
    recent moves: {list(recent_moves)}
    affect:       {ctx.affect_snapshot}
    open tensions: {ctx.open_tension_count}
    last 3 thoughts: {ctx.recent_thoughts[-3:]}
    """
    pick = cheap_model.complete(prompt).strip()
    assert pick in MENU
    if recent_moves and pick == recent_moves[-1]:
        pick = "rest"                  # no back-to-back
    return pick

function idle_tick(ctx):
    move_id = pick_move(ctx)
    recent_moves.append(move_id)
    MENU[move_id](ctx)                 # branch on move

QUIET_THRESHOLD = 4
state = load_json("juxtaposition.json",
                  default={"quiet_streak": 0})

function is_otherwise_quiet(ctx):
    return (ctx.chat_in_window is False and
            ctx.urgent_preoccupation is None and
            ctx.in_cooldown is False)

function sample_old_fragments(n):
    # Draw from any persistent corpus of past material:
    # thoughts, fragments, motivation lines, journal lines.
    return random_sample(load_old_material(), k=n)

function juxtaposition_tick(ctx):
    fragments = sample_old_fragments(n=random_int(1, 3))
    seed = {
        "mode": "juxtaposition",
        "fragments": fragments,
        "instruction": "sit with these side by side; ending empty is fine.",
    }
    out = model.complete(seed)
    if out and out.association_noticed:
        write_insight(out.text, sources=fragments)
    # else: tick closes silently. Empty is a first-class outcome.

function tick(ctx):
    if ctx.salience_low and is_otherwise_quiet(ctx):
        state.quiet_streak += 1
        if state.quiet_streak > QUIET_THRESHOLD:
            juxtaposition_tick(ctx)
            # don't reset on empty - only reset on a real active tick
            return
    else:
        state.quiet_streak = 0
    persist(state)
    run_normal_tick(ctx)

INNER_ALLOWLIST = {"inner_dialogue", "recall",
                   "register_affect", "exit_meditation"}
MODE_FILE = "state/meditation.json"
DEFAULT_BUDGET = 15 * MIN
INNER_TICK = 10 * SEC

function enter_meditation(budget=DEFAULT_BUDGET):
    write_json(MODE_FILE, {"on": True, "started_at": now(),
                            "budget": budget})

function in_meditation():
    s = read_json(MODE_FILE, default={"on": False})
    if not s.on: return False
    if now() - s.started_at > s.budget:
        clear(MODE_FILE); return False        # auto-exit
    return True

function dispatch(call):
    if in_meditation():
        if call.tool not in INNER_ALLOWLIST:
            return {"error": "public_write_blocked_in_meditation"}
        out = run_inner(call)
        append("journal/inner-dialogue/" + today(), out)
        return out
    return run_normal(call)

function next_tick_interval():
    return INNER_TICK if in_meditation() else NORMAL_TICK

MODES = {"idle": 60, "intense": 15}     # seconds
FLOOR, CEIL = 10, 600
INTENSE_LOCK_TICKS = 12
SALIENCE_THRESHOLD = 0.6

state = load_json("cadence.json",
    default={"mode": "idle", "lock_ticks_left": 0})

function score_salience(tick_result, external_impulse):
    return max(tick_result.novelty, external_impulse)   # 0..1

function next_interval(tick_result, external_impulse):
    s = score_salience(tick_result, external_impulse)
    if external_impulse > 0.0 or s >= SALIENCE_THRESHOLD:
        if state.mode != "intense":
            ledger.append("mode->intense", reason=s)
        state.mode = "intense"
        state.lock_ticks_left = INTENSE_LOCK_TICKS
    elif state.lock_ticks_left > 0:
        state.lock_ticks_left -= 1
    else:
        if state.mode != "idle":
            ledger.append("mode->idle")
        state.mode = "idle"
    persist(state)
    return clamp(MODES[state.mode], FLOOR, CEIL)

ledger = "tensions.jsonl"           # append-only
CURIOSITY_FLOOR = 0.1
DEFAULT_TTL = 7 * DAY
ASK_NOW = 0.7                       # intrusiveness threshold

function open_tension(topic, source, curiosity, intrusiveness,
                      ttl=DEFAULT_TTL):
    append_jsonl(ledger, {
        "kind": "open", "id": uuid(), "opened_at": now(),
        "topic": topic, "source": source,
        "curiosity": curiosity, "intrusiveness": intrusiveness,
        "expires_at": now() + ttl,
    })

function active_tensions(now):
    open_ids = set(); closed_ids = set()
    for e in read_jsonl(ledger):
        if e.kind == "open":   open_ids.add(e.id)
        if e.kind == "close":  closed_ids.add(e.ref)
    rows = [e for e in read_jsonl(ledger)
            if e.kind == "open" and e.id not in closed_ids
            and e.expires_at > now
            and e.curiosity >= CURIOSITY_FLOOR]
    return sorted(rows, key=lambda e: e.curiosity * e.intrusiveness,
                  reverse=True)

function next_move(now):
    top = active_tensions(now)[:5]
    if top and top[0].intrusiveness >= ASK_NOW:
        return ("ask_user", top[0])
    return ("store_quiet", top)

function close_tension(ref, resolution):
    append_jsonl(ledger, {"kind": "close", "ref": ref,
        "closed_at": now(), "resolution": resolution})

DIVERGENCE_PATTERNS = {
    "narration_loop":        detect_narration_loop,
    "frustration_path":      detect_frustration_path,
    "repetition_pressure":   detect_repetition_pressure,
}

function pre_tick_steer(recent_thoughts, recent_tool_calls,
                        affect, preoccupations) -> str | None:
    for pid, detector in DIVERGENCE_PATTERNS.items():
        suggested_move = detector(recent_thoughts, recent_tool_calls,
                                  affect, preoccupations)
        if suggested_move:
            steer = (f"[steering] divergence pattern {pid} "
                     f"detected; consider {suggested_move}")
            log_event("pre_tick_steer", pattern=pid,
                      move=suggested_move, ts=now())
            return steer
    log_event("pre_tick_steer", pattern=None, ts=now())
    return None

function build_prompt(base):
    hint = pre_tick_steer(*ctx_slices())
    if hint:
        base.append(system(hint))    # hint, not veto
    return base                       # generation proceeds either way

function self_archaeology_pass(now, window=30*DAY):
    thoughts = load_thoughts(since=now - window)
    by_topic = group_by(thoughts, key=topic_of)

    for topic, items in by_topic.items():
        periods = bucket_by_period(items, n=3)     # e.g. 3 periods
        positions = []
        for p in periods:
            stance = model.extract_position(p.items, topic=topic)
            positions.append({
                "period": p.label, "dates": p.range,
                "position": stance.text,
                "evidence": stance.evidence_refs,
            })
        note = render_trajectory_note(topic, positions)
        # one note per topic, dedicated surface
        write(f"surfaces/trajectory/{slug(topic)}.md", note)
        for prior in positions[:-1]:
            mark_superseded(topic, prior)

function surface_for_query(query):
    t = topic_of(query)
    note = read(f"surfaces/trajectory/{slug(t)}.md", default=None)
    if note:
        return [note] + raw_thoughts(t)     # trajectory first
    return raw_thoughts(t)

WINDOW = bounded_deque(maxlen=64)
DEFAULTS = {"N":4, "M":3, "K":5, "J":4, "G":40}
PER_TOOL = {"http_get": {"N": 6}, "shell": {"K": 3}}

function cap(tool, key):
    return PER_TOOL.get(tool, {}).get(key, DEFAULTS[key])

function precheck(tool, args, registry, state_probe):
    h = hash_args(args)
    WINDOW.append((now(), tool, h))
    recent = list(WINDOW)

    # 1 generic-repeat
    if count(recent, lambda e: e[1]==tool and e[2]==h) >= cap(tool,"N"):
        return trip("generic_repeat", tool, h)
    # 2 unknown-tool-repeat
    if tool not in registry:
        if count(recent, lambda e: e[1]==tool) >= cap(tool,"M"):
            return trip("unknown_tool_repeat", tool, h)
    # 3 poll-no-progress
    if state_probe.unchanged_for(tool) >= cap(tool,"K"):
        return trip("poll_no_progress", tool, h)
    # 4 ping-pong
    if ping_pong_cycles(recent) >= cap(tool,"J"):
        return trip("ping_pong", tool, h)
    # 5 global circuit-breaker
    if len(recent) >= cap(tool,"G"):
        return trip("global_breaker", tool, h)
    return None

function trip(mode, tool, h):
    return {"error": "tool_loop_detected", "mode": mode,
            "observed": {"tool": tool, "arg_hash": h,
                         "window_size": len(WINDOW)}}
